from dataclasses import dataclass

@dataclass
class EDPCommitment:
    annual_min_spend_usd: float        # contractual minimum
    projected_annual_spend_usd: float  # P50 forecast
    discount_rate: float               # e.g. 0.30 for 30%
    on_demand_annual_cost_usd: float   # what cost would be at list price

    @property
    def projected_savings_usd(self) -> float:
        """Savings vs. on-demand at projected consumption."""
        return self.on_demand_annual_cost_usd - self.projected_annual_spend_usd

    @property
    def coverage_ratio(self) -> float:
        """How much of the projected spend is covered by the minimum."""
        return self.annual_min_spend_usd / self.projected_annual_spend_usd

    @property
    def risk_exposure_usd(self) -> float:
        """Dollar amount at risk if consumption falls to minimum."""
        return max(self.annual_min_spend_usd - self.projected_annual_spend_usd, 0)

    def break_even_consumption_pct(self) -> float:
        """Consumption fraction at which EDP is cost-neutral vs. on-demand at list."""
        # At X% consumption: X * on_demand_rate = X * discounted_rate + (1-X)*min_commitment
        # Simplified: EDP worthwhile if savings from discount > minimum true-up
        no_edp_cost = self.projected_annual_spend_usd / (1 - self.discount_rate)
        return (self.annual_min_spend_usd / no_edp_cost) * 100

# Example: $1M minimum; projected spend $1.3M; 30% discount
edp = EDPCommitment(1_000_000, 1_300_000, 0.30, 1_857_143)  # on-demand equiv
print(f"Projected savings: ${edp.projected_savings_usd:,.0f}")
print(f"Coverage ratio: {edp.coverage_ratio:.0%}")
print(f"Risk exposure: ${edp.risk_exposure_usd:,.0f}")
